TypeScript

```
import { Handle, Position } from 'reactflow';

// Tailwind classes for Obsidian aesthetic: Dark grays, purple accents, sharp borders
const nodeStyles = "bg-[#1e1e1e] border-2 border-[#3f3f3f] rounded-md p-4 w-64 shadow-lg hover:border-purple-500 transition-colors";

export default function AgentNode({ data, isConnectable }) {
  return (
    <div className={nodeStyles}>
      {/* Header */}
      <div className="mb-2 border-b border-gray-700 pb-2">
        <span className="text-purple-400 font-mono text-xs uppercase font-bold">Agent</span>
      </div>

      {/* Inputs */}
      <div className="flex flex-col gap-2">
        <input 
          className="bg-[#2b2b2b] text-white text-sm p-1 rounded border border-gray-600 focus:outline-none focus:border-purple-400"
