### **2. Main Canvas: `EditorCanvas.tsx`**

This integrates the custom nodes and handles the "physics" (optional) or manual layout.

TypeScript

```
import ReactFlow, { 
  Background, 
  Controls, 
  MiniMap,
  useNodesState, 
  useEdgesState, 
  addEdge 
} from 'reactflow';
import 'reactflow/dist/style.css';

import AgentNode from '../Nodes/AgentNode';
import TaskNode from '../Nodes/TaskNode';
import RAGNode from '../Nodes/RAGNode';

// Register custom node types
const nodeTypes = {
  agent: AgentNode,
  task: TaskNode,
  rag: RAGNode,
};

// Obsidian Graph Style Settings
const bgStyle = { backgroundColor: '#111111' };
const defaultEdgeOptions = { 
  animated: true, 
  style: { stroke: '#a855f7', strokeWidth: 2 } // Purple edges
};

export default function EditorCanvas() {
  const [nodes, setNodes, onNodesChange] = useNodesState([

]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);

  const onConnect = (params) => setEdges((eds) => addEdge(params, eds));

  return (
    <div style={{ height: '100vh', width: '100%' }}>
      <ReactFlow
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={onConnect}
        nodeTypes={nodeTypes}
        defaultEdgeOptions={defaultEdgeOptions}
        style={bgStyle}
        fitView
      >
        <Background color="#333" gap={20} variant="dots" />
        <Controls className="bg-[#1e1e1e] border border-gray-700 fill-white" />
        <MiniMap 
          nodeColor={(n) => {
            if (n.type === 'agent') return '#a855f7'; // Purple
            if (n.type === 'rag') return '#22c55e';   // Green
            return '#fff';
          }}
          maskColor="rgba(0, 0, 0, 0.7)"
          className="bg-[#1e1e1e] border border-gray-700"
        />
      </ReactFlow>
    </div>
  );
}
```

