### **3. State Store: `useFlowStore.ts` (Zustand)**

You need a centralized store to extract the JSON configuration to send to your Python backend.

TypeScript

```
import { create } from 'zustand';
import { Node, Edge } from 'reactflow';

type FlowState = {
  nodes: Node[];
  edges: Edge[];
  // Function to serialize graph to CrewAI JSON format
  generateCrewConfig: () => any; 
};

export const useFlowStore = create<FlowState>((set, get) => ({
  nodes: [],
  edges: [],
  generateCrewConfig: () => {
    const { nodes, edges } = get();
    // Logic to map nodes/edges to { agents: [], tasks: [] }
    const agents = nodes.filter(n => n.type === 'agent').map(n => ({
      name: n.data.role,
      goal: n.data.goal
    }));
    return { agents }; // Expand logic here
  }
}));
```

