import threading
import time
from abc import ABC, abstractmethod
from typing import Dict, Any, List

class BaseAgent(ABC):
    &quot;&quot;&quot;Abstract base class for all AI agents&quot;&quot;&quot;

    def __init__(self, name: str, message_bus: MessageBus):
        self.name = name
        self.bus = message_bus
        self.running = False
        self.thread = None

    def start(self):
        &quot;&quot;&quot;Start the agent in a background thread&quot;&quot;&quot;
        self.running = True
        self.thread = threading.Thread(target=self._run_loop, daemon=

True)
        self.thread.start()

    def stop(self):
        &quot;&quot;&quot;Stop the agent&quot;&quot;&quot;
        self.running = False
        if self.thread:
            self.thread.join(timeout=5)

    def _run_loop(self):
        &quot;&quot;&quot;Main agent processing loop&quot;&quot;&quot;
        while self.running:
            try:
                messages = self.bus.receive_messages(self.name, max_messages=5)
                for message in messages:
                    self.process_message(message)
            except Exception as e:
                self.handle_error(e)

            time.sleep(0.1)  # Prevent busy waiting

    @abstractmethod
    def process_message(self, message: Dict[str, Any]):
        &quot;&quot;&quot;Process a received message - to be implemented by subclasses&quot;&quot;&quot;
        pass

    def send_message(self, recipient: str, payload: Any, priority: int = 2):
        &quot;&quot;&quot;Send message to another agent&quot;&quot;&quot;
        return self.bus.send_message(self.name, recipient, payload, priority)

    def handle_error(self, error: Exception):
        &quot;&quot;&quot;Handle processing errors - can be overridden&quot;&quot;&quot;
        print(f&quot;Agent {self.name} error: {error}&quot;)

class SwarmCoordinator:
    &quot;&quot;&quot;Coordinates multiple AI agents in a swarm&quot;&quot;&quot;

    def __init__(self, message_bus: MessageBus):
        self.bus = message_bus
        self.agents = {}

    def register_agent(self, agent: BaseAgent):
        &quot;&quot;&quot;Register an agent with the swarm&quot;&quot;&quot;
        self.agents[agent.name] = agent

    def start_swarm(self):
        &quot;&quot;&quot;Start all registered agents&quot;&quot;&quot;
        for agent in self.agents.values():
            agent.start()
            print(f&quot;Started agent: {agent.name}&quot;)

    def stop_swarm(self):
        &quot;&quot;&quot;Stop all registered agents&quot;&quot;&quot;
        for agent in self.agents.values():
            agent.stop()
            print(f&quot;Stopped agent: {agent.name}&quot;)

    def broadcast_message(self, payload: Any, priority: int = 2):
        &quot;&quot;&quot;Send message to all agents&quot;&quot;&quot;
        for agent_name in self.agents:
            self.bus.send_message(&quot;coordinator&quot;, agent_name, payload, priority)
